INSERT INTO `wp_comments` VALUES (1,1,'Комментатор WordPress','wapuu@wordpress.example','https://ru.wordpress.org/','','2026-03-07 21:59:35','2026-03-07 18:59:35','Привет! Это комментарий.\nЧтобы начать модерировать, редактировать и удалять комментарии, перейдите на экран «Комментарии» в консоли.\nАватары авторов комментариев загружаются с сервиса <a href=\"https://ru.gravatar.com/\">Gravatar</a>.',0,'1','','comment',0,0);
