INSERT INTO `wp_posts` VALUES (20,1,'2026-03-07 22:40:36','2026-03-07 19:40:36','/* ===== АНИМАЦИИ И СОВРЕМЕННЫЙ ДИЗАЙН ===== */\n\n/* Плавная прокрутка */\nhtml {\n    scroll-behavior: smooth;\n}\n\n/* Анимация появления элементов */\n@keyframes fadeInUp {\n    from {\n        opacity: 0;\n        transform: translateY(30px);\n    }\n    to {\n        opacity: 1;\n        transform: translateY(0);\n    }\n}\n\n@keyframes fadeIn {\n    from { opacity: 0; }\n    to { opacity: 1; }\n}\n\n@keyframes slideInLeft {\n    from {\n        opacity: 0;\n        transform: translateX(-50px);\n    }\n    to {\n        opacity: 1;\n        transform: translateX(0);\n    }\n}\n\n@keyframes goldShine {\n    0% { background-position: -200% center; }\n    100% { background-position: 200% center; }\n}\n\n/* Элементы с анимацией появления */\n.animate-fade-in {\n    animation: fadeInUp 0.8s ease-out;\n}\n\n.animate-fade-in-delay {\n    animation: fadeInUp 0.8s ease-out 0.2s backwards;\n}\n\n/* ===== ШАПКА САЙТА ===== */\n\n/* Современная шапка с тенью */\n.site-header {\n    box-shadow: 0 2px 20px rgba(0,0,0,0.1);\n    transition: all 0.3s ease;\n}\n\n.site-header.scrolled {\n    background: rgba(26, 26, 46, 0.98);\n    backdrop-filter: blur(10px);\n}\n\n/* Логотип с анимацией */\n.site-logo img {\n    transition: transform 0.3s ease;\n}\n\n.site-logo:hover img {\n    transform: scale(1.05);\n}\n\n/* ===== МЕНЮ С ВЫПАДАЮЩИМИ СПИСКАМИ ===== */\n\n/* Основные пункты меню */\n.main-navigation ul li {\n    position: relative;\n    margin: 0 5px;\n}\n\n.main-navigation ul li a {\n    color: #1a1a2e;\n    font-weight: 500;\n    padding: 15px 20px;\n    transition: all 0.3s ease;\n    position: relative;\n}\n\n.main-navigation ul li a:hover {\n    color: #c9a961;\n}\n\n/* Анимированная линия под пунктом меню */\n.main-navigation ul li a::after {\n    content: \'\';\n    position: absolute;\n    bottom: 10px;\n    left: 50%;\n    transform: translateX(-50%);\n    width: 0;\n    height: 2px;\n    background: linear-gradient(90deg, #c9a961, #d4b978);\n    transition: width 0.3s ease;\n}\n\n.main-navigation ul li a:hover::after {\n    width: 80%;\n}\n\n/* Выпадающее меню */\n.main-navigation ul ul {\n    background: #ffffff;\n    box-shadow: 0 10px 40px rgba(0,0,0,0.15);\n    border-radius: 8px;\n    border-top: 3px solid #c9a961;\n    opacity: 0;\n    visibility: hidden;\n    transform: translateY(10px);\n    transition: all 0.3s ease;\n    min-width: 250px;\n    padding: 10px 0;\n}\n\n.main-navigation ul li:hover > ul {\n    opacity: 1;\n    visibility: visible;\n    transform: translateY(0);\n}\n\n.main-navigation ul ul li {\n    margin: 0;\n}\n\n.main-navigation ul ul li a {\n    padding: 12px 25px;\n    color: #2d2d2d;\n    font-size: 14px;\n    border-left: 3px solid transparent;\n    transition: all 0.3s ease;\n}\n\n.main-navigation ul ul li a:hover {\n    background: #faf8f5;\n    color: #c9a961;\n    border-left-color: #c9a961;\n    padding-left: 30px;\n}\n\n/* Иконка стрелки для выпадающего меню */\n.main-navigation .menu-item-has-children > a::before {\n    content: \'▼\';\n    font-size: 8px;\n    margin-left: 8px;\n    transition: transform 0.3s ease;\n}\n\n.main-navigation .menu-item-has-children:hover > a::before {\n    transform: rotate(180deg);\n}\n\n/* ===== ГЛАВНЫЙ БАННЕР (HERO) ===== */\n\n.hero-section {\n    position: relative;\n    min-height: 600px;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    background: linear-gradient(135deg, #1a1a2e 0%, #2d2d44 100%);\n    overflow: hidden;\n}\n\n.hero-section::before {\n    content: \'\';\n    position: absolute;\n    top: 0;\n    left: 0;\n    right: 0;\n    bottom: 0;\n    background: url(\'path-to-church-image.jpg\') center/cover;\n    opacity: 0.3;\n}\n\n.hero-content {\n    position: relative;\n    z-index: 2;\n    text-align: center;\n    color: white;\n    padding: 60px 20px;\n}\n\n.hero-title {\n    font-size: 48px;\n    font-weight: 700;\n    margin-bottom: 20px;\n    background: linear-gradient(90deg, #c9a961, #f0e6c8, #c9a961);\n    background-size: 200% auto;\n    -webkit-background-clip: text;\n    -webkit-text-fill-color: transparent;\n    animation: goldShine 3s linear infinite;\n}\n\n.hero-subtitle {\n    font-size: 24px;\n    margin-bottom: 40px;\n    opacity: 0.9;\n}\n\n.hero-button {\n    display: inline-block;\n    padding: 15px 40px;\n    background: linear-gradient(135deg, #c9a961, #b8960c);\n    color: #1a1a2e;\n    text-decoration: none;\n    border-radius: 50px;\n    font-weight: 600;\n    transition: all 0.3s ease;\n    box-shadow: 0 10px 30px rgba(201, 169, 97, 0.3);\n}\n\n.hero-button:hover {\n    transform: translateY(-3px);\n    box-shadow: 0 15px 40px rgba(201, 169, 97, 0.4);\n}\n\n/* ===== КАРТОЧКИ С АНИМАЦИЕЙ ===== */\n\n.feature-card {\n    background: white;\n    border-radius: 15px;\n    padding: 40px 30px;\n    text-align: center;\n    box-shadow: 0 5px 20px rgba(0,0,0,0.08);\n    transition: all 0.3s ease;\n    border-bottom: 3px solid transparent;\n}\n\n.feature-card:hover {\n    transform: translateY(-10px);\n    box-shadow: 0 15px 40px rgba(0,0,0,0.12);\n    border-bottom-color: #c9a961;\n}\n\n.feature-icon {\n    font-size: 48px;\n    margin-bottom: 20px;\n    color: #c9a961;\n}\n\n/* ===== РАСПИСАНИЕ БОГОСЛУЖЕНИЙ ===== */\n\n.service-schedule {\n    background: linear-gradient(135deg, #faf8f5, #f5f0e8);\n    padding: 60px 40px;\n    border-radius: 20px;\n    margin: 40px 0;\n}\n\n.service-item {\n    background: white;\n    padding: 25px;\n    margin: 15px 0;\n    border-radius: 10px;\n    border-left: 4px solid #c9a961;\n    transition: all 0.3s ease;\n}\n\n.service-item:hover {\n    box-shadow: 0 5px 20px rgba(0,0,0,0.1);\n    transform: translateX(5px);\n}\n\n.service-time {\n    color: #c9a961;\n    font-weight: 700;\n    font-size: 18px;\n}\n\n/* ===== НОВОСТИ С АНИМАЦИЕЙ ===== */\n\n.news-card {\n    background: white;\n    border-radius: 12px;\n    overflow: hidden;\n    box-shadow: 0 5px 20px rgba(0,0,0,0.08);\n    transition: all 0.3s ease;\n}\n\n.news-card:hover {\n    transform: translateY(-5px);\n    box-shadow: 0 10px 30px rgba(0,0,0,0.15);\n}\n\n.news-date {\n    background: #c9a961;\n    color: white;\n    padding: 10px 20px;\n    display: inline-block;\n    border-radius: 5px;\n    font-weight: 600;\n}\n\n/* ===== КНОПКА ПОЖЕРТВОВАНИЯ ===== */\n\n.donate-button {\n    background: linear-gradient(135deg, #8b2635, #a63042);\n    color: white;\n    padding: 18px 45px;\n    border-radius: 50px;\n    text-decoration: none;\n    display: inline-block;\n    font-weight: 600;\n    transition: all 0.3s ease;\n    box-shadow: 0 10px 30px rgba(139, 38, 53, 0.3);\n}\n\n.donate-button:hover {\n    transform: translateY(-3px) scale(1.02);\n    box-shadow: 0 15px 40px rgba(139, 38, 53, 0.4);\n}\n\n/* ===== ПОДВАЛ (FOOTER) ===== */\n\n.site-footer {\n    background: #1a1a2e;\n    color: white;\n    padding: 60px 0 30px;\n}\n\n.footer-widget h3 {\n    color: #c9a961;\n    margin-bottom: 20px;\n}\n\n.footer-bottom {\n    border-top: 1px solid rgba(201, 169, 97, 0.3);\n    margin-top: 40px;\n    padding-top: 20px;\n    text-align: center;\n    color: rgba(255,255,255,0.6);\n}\n\n/* ===== АДАПТИВНОСТЬ ===== */\n\n@media (max-width: 768px) {\n    .hero-title {\n        font-size: 32px;\n    }\n    \n    .hero-subtitle {\n        font-size: 18px;\n    }\n    \n    .main-navigation ul ul {\n        min-width: 200px;\n    }\n}\n\n/* ===== ДОПОЛНИТЕЛЬНЫЕ ЭФФЕКТЫ ===== */\n\n/* Золотой блеск для заголовков */\n.gold-text {\n    background: linear-gradient(90deg, #c9a961, #f0e6c8, #c9a961);\n    background-size: 200% auto;\n    -webkit-background-clip: text;\n    -webkit-text-fill-color: transparent;\n    animation: goldShine 3s linear infinite;\n}\n\n/* Разделитель с орнаментом */\n.ornament-divider {\n    text-align: center;\n    margin: 40px 0;\n    font-size: 24px;\n    color: #c9a961;\n}\n\n/* Плавное появление при скролле */\n.scroll-reveal {\n    opacity: 0;\n    transform: translateY(30px);\n    transition: all 0.8s ease;\n}\n\n.scroll-reveal.active {\n    opacity: 1;\n    transform: translateY(0);\n}','kadence','','publish','closed','closed','','kadence','','','2026-03-07 22:40:36','2026-03-07 19:40:36','',0,'http://danil.local/kadence/',0,'custom_css','',0);
INSERT INTO `wp_posts` VALUES (21,1,'2026-03-07 22:40:36','2026-03-07 19:40:36','/* ===== АНИМАЦИИ И СОВРЕМЕННЫЙ ДИЗАЙН ===== */\n\n/* Плавная прокрутка */\nhtml {\n    scroll-behavior: smooth;\n}\n\n/* Анимация появления элементов */\n@keyframes fadeInUp {\n    from {\n        opacity: 0;\n        transform: translateY(30px);\n    }\n    to {\n        opacity: 1;\n        transform: translateY(0);\n    }\n}\n\n@keyframes fadeIn {\n    from { opacity: 0; }\n    to { opacity: 1; }\n}\n\n@keyframes slideInLeft {\n    from {\n        opacity: 0;\n        transform: translateX(-50px);\n    }\n    to {\n        opacity: 1;\n        transform: translateX(0);\n    }\n}\n\n@keyframes goldShine {\n    0% { background-position: -200% center; }\n    100% { background-position: 200% center; }\n}\n\n/* Элементы с анимацией появления */\n.animate-fade-in {\n    animation: fadeInUp 0.8s ease-out;\n}\n\n.animate-fade-in-delay {\n    animation: fadeInUp 0.8s ease-out 0.2s backwards;\n}\n\n/* ===== ШАПКА САЙТА ===== */\n\n/* Современная шапка с тенью */\n.site-header {\n    box-shadow: 0 2px 20px rgba(0,0,0,0.1);\n    transition: all 0.3s ease;\n}\n\n.site-header.scrolled {\n    background: rgba(26, 26, 46, 0.98);\n    backdrop-filter: blur(10px);\n}\n\n/* Логотип с анимацией */\n.site-logo img {\n    transition: transform 0.3s ease;\n}\n\n.site-logo:hover img {\n    transform: scale(1.05);\n}\n\n/* ===== МЕНЮ С ВЫПАДАЮЩИМИ СПИСКАМИ ===== */\n\n/* Основные пункты меню */\n.main-navigation ul li {\n    position: relative;\n    margin: 0 5px;\n}\n\n.main-navigation ul li a {\n    color: #1a1a2e;\n    font-weight: 500;\n    padding: 15px 20px;\n    transition: all 0.3s ease;\n    position: relative;\n}\n\n.main-navigation ul li a:hover {\n    color: #c9a961;\n}\n\n/* Анимированная линия под пунктом меню */\n.main-navigation ul li a::after {\n    content: \'\';\n    position: absolute;\n    bottom: 10px;\n    left: 50%;\n    transform: translateX(-50%);\n    width: 0;\n    height: 2px;\n    background: linear-gradient(90deg, #c9a961, #d4b978);\n    transition: width 0.3s ease;\n}\n\n.main-navigation ul li a:hover::after {\n    width: 80%;\n}\n\n/* Выпадающее меню */\n.main-navigation ul ul {\n    background: #ffffff;\n    box-shadow: 0 10px 40px rgba(0,0,0,0.15);\n    border-radius: 8px;\n    border-top: 3px solid #c9a961;\n    opacity: 0;\n    visibility: hidden;\n    transform: translateY(10px);\n    transition: all 0.3s ease;\n    min-width: 250px;\n    padding: 10px 0;\n}\n\n.main-navigation ul li:hover > ul {\n    opacity: 1;\n    visibility: visible;\n    transform: translateY(0);\n}\n\n.main-navigation ul ul li {\n    margin: 0;\n}\n\n.main-navigation ul ul li a {\n    padding: 12px 25px;\n    color: #2d2d2d;\n    font-size: 14px;\n    border-left: 3px solid transparent;\n    transition: all 0.3s ease;\n}\n\n.main-navigation ul ul li a:hover {\n    background: #faf8f5;\n    color: #c9a961;\n    border-left-color: #c9a961;\n    padding-left: 30px;\n}\n\n/* Иконка стрелки для выпадающего меню */\n.main-navigation .menu-item-has-children > a::before {\n    content: \'▼\';\n    font-size: 8px;\n    margin-left: 8px;\n    transition: transform 0.3s ease;\n}\n\n.main-navigation .menu-item-has-children:hover > a::before {\n    transform: rotate(180deg);\n}\n\n/* ===== ГЛАВНЫЙ БАННЕР (HERO) ===== */\n\n.hero-section {\n    position: relative;\n    min-height: 600px;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    background: linear-gradient(135deg, #1a1a2e 0%, #2d2d44 100%);\n    overflow: hidden;\n}\n\n.hero-section::before {\n    content: \'\';\n    position: absolute;\n    top: 0;\n    left: 0;\n    right: 0;\n    bottom: 0;\n    background: url(\'path-to-church-image.jpg\') center/cover;\n    opacity: 0.3;\n}\n\n.hero-content {\n    position: relative;\n    z-index: 2;\n    text-align: center;\n    color: white;\n    padding: 60px 20px;\n}\n\n.hero-title {\n    font-size: 48px;\n    font-weight: 700;\n    margin-bottom: 20px;\n    background: linear-gradient(90deg, #c9a961, #f0e6c8, #c9a961);\n    background-size: 200% auto;\n    -webkit-background-clip: text;\n    -webkit-text-fill-color: transparent;\n    animation: goldShine 3s linear infinite;\n}\n\n.hero-subtitle {\n    font-size: 24px;\n    margin-bottom: 40px;\n    opacity: 0.9;\n}\n\n.hero-button {\n    display: inline-block;\n    padding: 15px 40px;\n    background: linear-gradient(135deg, #c9a961, #b8960c);\n    color: #1a1a2e;\n    text-decoration: none;\n    border-radius: 50px;\n    font-weight: 600;\n    transition: all 0.3s ease;\n    box-shadow: 0 10px 30px rgba(201, 169, 97, 0.3);\n}\n\n.hero-button:hover {\n    transform: translateY(-3px);\n    box-shadow: 0 15px 40px rgba(201, 169, 97, 0.4);\n}\n\n/* ===== КАРТОЧКИ С АНИМАЦИЕЙ ===== */\n\n.feature-card {\n    background: white;\n    border-radius: 15px;\n    padding: 40px 30px;\n    text-align: center;\n    box-shadow: 0 5px 20px rgba(0,0,0,0.08);\n    transition: all 0.3s ease;\n    border-bottom: 3px solid transparent;\n}\n\n.feature-card:hover {\n    transform: translateY(-10px);\n    box-shadow: 0 15px 40px rgba(0,0,0,0.12);\n    border-bottom-color: #c9a961;\n}\n\n.feature-icon {\n    font-size: 48px;\n    margin-bottom: 20px;\n    color: #c9a961;\n}\n\n/* ===== РАСПИСАНИЕ БОГОСЛУЖЕНИЙ ===== */\n\n.service-schedule {\n    background: linear-gradient(135deg, #faf8f5, #f5f0e8);\n    padding: 60px 40px;\n    border-radius: 20px;\n    margin: 40px 0;\n}\n\n.service-item {\n    background: white;\n    padding: 25px;\n    margin: 15px 0;\n    border-radius: 10px;\n    border-left: 4px solid #c9a961;\n    transition: all 0.3s ease;\n}\n\n.service-item:hover {\n    box-shadow: 0 5px 20px rgba(0,0,0,0.1);\n    transform: translateX(5px);\n}\n\n.service-time {\n    color: #c9a961;\n    font-weight: 700;\n    font-size: 18px;\n}\n\n/* ===== НОВОСТИ С АНИМАЦИЕЙ ===== */\n\n.news-card {\n    background: white;\n    border-radius: 12px;\n    overflow: hidden;\n    box-shadow: 0 5px 20px rgba(0,0,0,0.08);\n    transition: all 0.3s ease;\n}\n\n.news-card:hover {\n    transform: translateY(-5px);\n    box-shadow: 0 10px 30px rgba(0,0,0,0.15);\n}\n\n.news-date {\n    background: #c9a961;\n    color: white;\n    padding: 10px 20px;\n    display: inline-block;\n    border-radius: 5px;\n    font-weight: 600;\n}\n\n/* ===== КНОПКА ПОЖЕРТВОВАНИЯ ===== */\n\n.donate-button {\n    background: linear-gradient(135deg, #8b2635, #a63042);\n    color: white;\n    padding: 18px 45px;\n    border-radius: 50px;\n    text-decoration: none;\n    display: inline-block;\n    font-weight: 600;\n    transition: all 0.3s ease;\n    box-shadow: 0 10px 30px rgba(139, 38, 53, 0.3);\n}\n\n.donate-button:hover {\n    transform: translateY(-3px) scale(1.02);\n    box-shadow: 0 15px 40px rgba(139, 38, 53, 0.4);\n}\n\n/* ===== ПОДВАЛ (FOOTER) ===== */\n\n.site-footer {\n    background: #1a1a2e;\n    color: white;\n    padding: 60px 0 30px;\n}\n\n.footer-widget h3 {\n    color: #c9a961;\n    margin-bottom: 20px;\n}\n\n.footer-bottom {\n    border-top: 1px solid rgba(201, 169, 97, 0.3);\n    margin-top: 40px;\n    padding-top: 20px;\n    text-align: center;\n    color: rgba(255,255,255,0.6);\n}\n\n/* ===== АДАПТИВНОСТЬ ===== */\n\n@media (max-width: 768px) {\n    .hero-title {\n        font-size: 32px;\n    }\n    \n    .hero-subtitle {\n        font-size: 18px;\n    }\n    \n    .main-navigation ul ul {\n        min-width: 200px;\n    }\n}\n\n/* ===== ДОПОЛНИТЕЛЬНЫЕ ЭФФЕКТЫ ===== */\n\n/* Золотой блеск для заголовков */\n.gold-text {\n    background: linear-gradient(90deg, #c9a961, #f0e6c8, #c9a961);\n    background-size: 200% auto;\n    -webkit-background-clip: text;\n    -webkit-text-fill-color: transparent;\n    animation: goldShine 3s linear infinite;\n}\n\n/* Разделитель с орнаментом */\n.ornament-divider {\n    text-align: center;\n    margin: 40px 0;\n    font-size: 24px;\n    color: #c9a961;\n}\n\n/* Плавное появление при скролле */\n.scroll-reveal {\n    opacity: 0;\n    transform: translateY(30px);\n    transition: all 0.8s ease;\n}\n\n.scroll-reveal.active {\n    opacity: 1;\n    transform: translateY(0);\n}','kadence','','inherit','closed','closed','','20-revision-v1','','','2026-03-07 22:40:36','2026-03-07 19:40:36','',20,'http://danil.local/?p=21',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (23,1,'2026-03-08 14:06:01','2026-03-08 11:06:01','<!-- wp:kadence/rowlayout {\"uniqueID\":\"23_feed71-9e\",\"columns\":1,\"colLayout\":\"equal\",\"firstColumnWidth\":0,\"secondColumnWidth\":0,\"thirdColumnWidth\":0,\"fourthColumnWidth\":0,\"fifthColumnWidth\":0,\"sixthColumnWidth\":0,\"kbVersion\":2} -->\n<!-- wp:kadence/column {\"borderWidth\":[\"\",\"\",\"\",\"\"],\"uniqueID\":\"23_b74723-33\",\"kbVersion\":2} -->\n<div class=\"wp-block-kadence-column kadence-column23_b74723-33\"><div class=\"kt-inside-inner-col\"></div></div>\n<!-- /wp:kadence/column -->\n<!-- /wp:kadence/rowlayout -->','Главная','','publish','closed','closed','','%d0%b3%d0%bb%d0%b0%d0%b2%d0%bd%d0%b0%d1%8f','','','2026-03-08 14:06:01','2026-03-08 11:06:01','',0,'http://danil.local/?page_id=23',0,'page','',0);
INSERT INTO `wp_posts` VALUES (26,1,'2026-03-08 12:24:13','2026-03-08 09:24:13','/*\nTheme Name: Church Kadence Child\nTheme URI: http://danil.local/\nDescription: Дочерняя тема для храма на базе Kadence\nAuthor: Ваше Имя\nTemplate: kadence\nVersion: 1.0.0\nText Domain: church-kadence-child\n*/\n\n/* ===== БАЗОВЫЕ НАСТРОЙКИ ===== */\n:root {\n    --color-primary: #1a1a2e;\n    --color-accent: #c9a961;\n    --color-accent-hover: #b8960c;\n    --color-secondary: #8b2635;\n    --color-bg: #faf8f5;\n    --color-text: #2d2d2d;\n    --color-text-light: #666;\n    --shadow-card: 0 5px 20px rgba(0,0,0,0.08);\n    --shadow-hover: 0 15px 40px rgba(0,0,0,0.12);\n    --radius: 12px;\n    --transition: all 0.3s ease;\n}\n\n* { box-sizing: border-box; margin: 0; padding: 0; }\n\nbody {\n    font-family: \'Inter\', sans-serif;\n    color: var(--color-text);\n    background: var(--color-bg);\n    line-height: 1.6;\n}\n\nh1, h2, h3, h4 {\n    font-family: \'Playfair Display\', serif;\n    color: var(--color-primary);\n    line-height: 1.3;\n}\n\na { text-decoration: none; color: inherit; transition: var(--transition); }\nimg { max-width: 100%; height: auto; display: block; }\n\n.container {\n    max-width: 1200px;\n    margin: 0 auto;\n    padding: 0 20px;\n}\n\n/* ===== АНИМАЦИИ ===== */\n@keyframes fadeInUp {\n    from { opacity: 0; transform: translateY(30px); }\n    to { opacity: 1; transform: translateY(0); }\n}\n\n@keyframes goldShine {\n    0% { background-position: -200% center; }\n    100% { background-position: 200% center; }\n}\n\n.animate-fade-in { animation: fadeInUp 0.8s ease-out forwards; }\n.animate-fade-in-delay { animation: fadeInUp 0.8s ease-out 0.2s backwards; }\n\n.gold-text {\n    background: linear-gradient(90deg, var(--color-accent), #f0e6c8, var(--color-accent));\n    background-size: 200% auto;\n    -webkit-background-clip: text;\n    -webkit-text-fill-color: transparent;\n    animation: goldShine 3s linear infinite;\n}\n\n/* Плавное появление при скролле */\n.scroll-reveal {\n    opacity: 0;\n    transform: translateY(30px);\n    transition: all 0.6s ease;\n}\n.scroll-reveal.active {\n    opacity: 1;\n    transform: translateY(0);\n}\n\n/* ===== ШАПКА ===== */\n.site-header {\n    background: white;\n    box-shadow: 0 2px 20px rgba(0,0,0,0.08);\n    position: sticky;\n    top: 0;\n    z-index: 1000;\n}\n\n.header-inner {\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    padding: 15px 0;\n}\n\n.logo img {\n    height: 60px;\n    transition: transform 0.3s ease;\n}\n.logo:hover img { transform: scale(1.05); }\n\n/* Меню */\n.main-navigation ul {\n    display: flex;\n    list-style: none;\n    gap: 5px;\n    margin: 0;\n    padding: 0;\n}\n\n.main-navigation ul li { position: relative; }\n\n.main-navigation ul li a {\n    padding: 12px 18px;\n    font-weight: 500;\n    color: var(--color-primary);\n    border-radius: 6px;\n    transition: var(--transition);\n}\n\n.main-navigation ul li a:hover,\n.main-navigation ul li.current-menu-item > a {\n    color: var(--color-accent);\n    background: rgba(201, 169, 97, 0.1);\n}\n\n/* Выпадающее меню */\n.main-navigation ul ul {\n    position: absolute;\n    top: 100%;\n    left: 0;\n    background: white;\n    min-width: 240px;\n    border-radius: 8px;\n    box-shadow: 0 10px 40px rgba(0,0,0,0.15);\n    border-top: 3px solid var(--color-accent);\n    opacity: 0;\n    visibility: hidden;\n    transform: translateY(10px);\n    transition: var(--transition);\n    flex-direction: column;\n    padding: 8px 0;\n}\n\n.main-navigation ul li:hover > ul {\n    opacity: 1;\n    visibility: visible;\n    transform: translateY(0);\n}\n\n.main-navigation ul ul a {\n    padding: 10px 20px;\n    font-size: 14px;\n    border-left: 3px solid transparent;\n}\n\n.main-navigation ul ul a:hover {\n    background: var(--color-bg);\n    color: var(--color-accent);\n    border-left-color: var(--color-accent);\n    padding-left: 25px;\n}\n\n/* Стрелочка для подменю */\n.menu-item-has-children > a::after {\n    content: \'▼\';\n    font-size: 8px;\n    margin-left: 6px;\n    transition: transform 0.3s ease;\n}\n.menu-item-has-children:hover > a::after { transform: rotate(180deg); }\n\n/* Кнопка пожертвования в меню */\n.donate-menu-item a {\n    background: linear-gradient(135deg, var(--color-secondary), #a63042);\n    color: white !important;\n    padding: 10px 25px !important;\n    border-radius: 50px;\n    font-weight: 600;\n}\n.donate-menu-item a:hover {\n    transform: translateY(-2px);\n    box-shadow: 0 10px 30px rgba(139, 38, 53, 0.3);\n}\n\n/* ===== HERO СЕКЦИЯ ===== */\n.hero {\n    position: relative;\n    min-height: 550px;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    background: linear-gradient(135deg, var(--color-primary) 0%, #2d2d44 100%);\n    text-align: center;\n    color: white;\n    padding: 60px 20px;\n    overflow: hidden;\n}\n\n.hero::before {\n    content: \'\';\n    position: absolute;\n    inset: 0;\n    background: url(\'../images/hero-bg.jpg\') center/cover;\n    opacity: 0.15;\n}\n\n.hero-content {\n    position: relative;\n    z-index: 2;\n    max-width: 800px;\n}\n\n.hero-title {\n    font-size: 42px;\n    margin-bottom: 20px;\n    color: white;\n}\n\n.hero-subtitle {\n    font-size: 20px;\n    opacity: 0.95;\n    margin-bottom: 35px;\n}\n\n.hero-button {\n    display: inline-block;\n    padding: 16px 45px;\n    background: linear-gradient(135deg, var(--color-accent), var(--color-accent-hover));\n    color: var(--color-primary) !important;\n    border-radius: 50px;\n    font-weight: 600;\n    font-size: 16px;\n    box-shadow: 0 10px 30px rgba(201, 169, 97, 0.3);\n}\n.hero-button:hover {\n    transform: translateY(-3px);\n    box-shadow: 0 15px 40px rgba(201, 169, 97, 0.4);\n}\n\n/* ===== КАРТОЧКИ УСЛУГ ===== */\n.services-section {\n    padding: 80px 0;\n    background: white;\n}\n\n.section-title {\n    text-align: center;\n    margin-bottom: 50px;\n}\n.section-title h2 {\n    font-size: 32px;\n    margin-bottom: 15px;\n}\n.section-title p {\n    color: var(--color-text-light);\n    max-width: 600px;\n    margin: 0 auto;\n}\n\n.services-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));\n    gap: 30px;\n}\n\n.service-card {\n    background: var(--color-bg);\n    border-radius: var(--radius);\n    padding: 35px 30px;\n    text-align: center;\n    box-shadow: var(--shadow-card);\n    transition: var(--transition);\n    border-bottom: 3px solid transparent;\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n}\n\n.service-card:hover {\n    transform: translateY(-8px);\n    box-shadow: var(--shadow-hover);\n    border-bottom-color: var(--color-accent);\n}\n\n.service-icon {\n    width: 70px;\n    height: 70px;\n    background: linear-gradient(135deg, var(--color-accent), var(--color-accent-hover));\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    margin-bottom: 20px;\n    font-size: 28px;\n    color: var(--color-primary);\n}\n\n.service-card h3 {\n    font-size: 20px;\n    margin-bottom: 12px;\n}\n\n.service-card p {\n    color: var(--color-text-light);\n    margin-bottom: 20px;\n    flex-grow: 1;\n}\n\n.service-link {\n    color: var(--color-secondary);\n    font-weight: 500;\n    display: inline-flex;\n    align-items: center;\n    gap: 5px;\n}\n.service-link:hover { gap: 10px; }\n\n/* ===== БЛОК НОВОСТЕЙ ===== */\n.news-section {\n    padding: 80px 0;\n    background: var(--color-bg);\n}\n\n.news-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));\n    gap: 30px;\n}\n\n.news-card {\n    background: white;\n    border-radius: var(--radius);\n    overflow: hidden;\n    box-shadow: var(--shadow-card);\n    transition: var(--transition);\n}\n.news-card:hover {\n    transform: translateY(-5px);\n    box-shadow: var(--shadow-hover);\n}\n\n.news-image {\n    height: 200px;\n    background: #ddd;\n    background-size: cover;\n    background-position: center;\n}\n\n.news-content {\n    padding: 25px;\n}\n\n.news-date {\n    display: inline-block;\n    padding: 5px 15px;\n    background: var(--color-accent);\n    color: var(--color-primary);\n    border-radius: 20px;\n    font-size: 13px;\n    font-weight: 600;\n    margin-bottom: 12px;\n}\n\n.news-card h3 {\n    font-size: 18px;\n    margin-bottom: 10px;\n}\n\n.news-excerpt {\n    color: var(--color-text-light);\n    font-size: 14px;\n    margin-bottom: 15px;\n}\n\n.news-read-more {\n    color: var(--color-secondary);\n    font-weight: 500;\n    font-size: 14px;\n}\n\n/* ===== РАСПИСАНИЕ ===== */\n.schedule-section {\n    padding: 60px 0;\n}\n\n.schedule-table {\n    background: white;\n    border-radius: var(--radius);\n    box-shadow: var(--shadow-card);\n    overflow: hidden;\n}\n\n.schedule-row {\n    display: grid;\n    grid-template-columns: 1fr 2fr 1fr;\n    padding: 20px 25px;\n    border-bottom: 1px solid #eee;\n    align-items: center;\n    transition: var(--transition);\n}\n.schedule-row:last-child { border-bottom: none; }\n.schedule-row:hover { background: var(--color-bg); }\n\n.schedule-day { font-weight: 600; color: var(--color-primary); }\n.schedule-service { color: var(--color-text); }\n.schedule-time {\n    background: var(--color-accent);\n    color: var(--color-primary);\n    padding: 5px 15px;\n    border-radius: 20px;\n    font-weight: 600;\n    font-size: 14px;\n    text-align: center;\n}\n\n/* ===== ПОДВАЛ ===== */\n.site-footer {\n    background: var(--color-primary);\n    color: white;\n    padding: 60px 0 30px;\n}\n\n.footer-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));\n    gap: 40px;\n    margin-bottom: 40px;\n}\n\n.footer-widget h4 {\n    color: var(--color-accent);\n    margin-bottom: 20px;\n    font-size: 18px;\n}\n\n.footer-widget ul { list-style: none; }\n.footer-widget ul li { margin-bottom: 10px; }\n.footer-widget ul li a {\n    color: rgba(255,255,255,0.8);\n    transition: var(--transition);\n}\n.footer-widget ul li a:hover {\n    color: var(--color-accent);\n    padding-left: 5px;\n}\n\n.footer-bottom {\n    text-align: center;\n    padding-top: 25px;\n    border-top: 1px solid rgba(201, 169, 97, 0.3);\n    color: rgba(255,255,255,0.6);\n    font-size: 14px;\n}\n\n/* ===== АДАПТИВНОСТЬ ===== */\n@media (max-width: 992px) {\n    .main-navigation ul {\n        flex-wrap: wrap;\n        justify-content: center;\n    }\n    .hero-title { font-size: 36px; }\n}\n\n@media (max-width: 768px) {\n    .header-inner { flex-wrap: wrap; }\n    \n    .main-navigation {\n        order: 3;\n        width: 100%;\n        margin-top: 15px;\n    }\n    \n    .main-navigation ul {\n        flex-direction: column;\n        align-items: center;\n    }\n    \n    .main-navigation ul ul {\n        position: static;\n        opacity: 1;\n        visibility: visible;\n        transform: none;\n        box-shadow: none;\n        border-top: none;\n        border-left: 3px solid var(--color-accent);\n        margin-left: 15px;\n        margin-top: 5px;\n        padding-left: 10px;\n    }\n    \n    .hero-title { font-size: 28px; }\n    .hero-subtitle { font-size: 18px; }\n    \n    .schedule-row {\n        grid-template-columns: 1fr;\n        gap: 10px;\n        text-align: center;\n    }\n}','church-kadence-child','','publish','closed','closed','','church-kadence-child','','','2026-03-08 12:24:50','2026-03-08 09:24:50','',0,'http://danil.local/church-kadence-child/',0,'custom_css','',0);
INSERT INTO `wp_posts` VALUES (27,1,'2026-03-08 12:24:13','2026-03-08 09:24:13','/*\nTheme Name: Church Kadence Child\nTheme URI: https://alexander-nevskiysobor.ru\nDescription: Дочерняя тема для храма на базе Kadence\nAuthor: Ваше Имя\nTemplate: kadence\nVersion: 1.0.0\nText Domain: church-kadence-child\n*/\n\n/* ===== БАЗОВЫЕ НАСТРОЙКИ ===== */\n:root {\n    --color-primary: #1a1a2e;\n    --color-accent: #c9a961;\n    --color-accent-hover: #b8960c;\n    --color-secondary: #8b2635;\n    --color-bg: #faf8f5;\n    --color-text: #2d2d2d;\n    --color-text-light: #666;\n    --shadow-card: 0 5px 20px rgba(0,0,0,0.08);\n    --shadow-hover: 0 15px 40px rgba(0,0,0,0.12);\n    --radius: 12px;\n    --transition: all 0.3s ease;\n}\n\n* { box-sizing: border-box; margin: 0; padding: 0; }\n\nbody {\n    font-family: \'Inter\', sans-serif;\n    color: var(--color-text);\n    background: var(--color-bg);\n    line-height: 1.6;\n}\n\nh1, h2, h3, h4 {\n    font-family: \'Playfair Display\', serif;\n    color: var(--color-primary);\n    line-height: 1.3;\n}\n\na { text-decoration: none; color: inherit; transition: var(--transition); }\nimg { max-width: 100%; height: auto; display: block; }\n\n.container {\n    max-width: 1200px;\n    margin: 0 auto;\n    padding: 0 20px;\n}\n\n/* ===== АНИМАЦИИ ===== */\n@keyframes fadeInUp {\n    from { opacity: 0; transform: translateY(30px); }\n    to { opacity: 1; transform: translateY(0); }\n}\n\n@keyframes goldShine {\n    0% { background-position: -200% center; }\n    100% { background-position: 200% center; }\n}\n\n.animate-fade-in { animation: fadeInUp 0.8s ease-out forwards; }\n.animate-fade-in-delay { animation: fadeInUp 0.8s ease-out 0.2s backwards; }\n\n.gold-text {\n    background: linear-gradient(90deg, var(--color-accent), #f0e6c8, var(--color-accent));\n    background-size: 200% auto;\n    -webkit-background-clip: text;\n    -webkit-text-fill-color: transparent;\n    animation: goldShine 3s linear infinite;\n}\n\n/* Плавное появление при скролле */\n.scroll-reveal {\n    opacity: 0;\n    transform: translateY(30px);\n    transition: all 0.6s ease;\n}\n.scroll-reveal.active {\n    opacity: 1;\n    transform: translateY(0);\n}\n\n/* ===== ШАПКА ===== */\n.site-header {\n    background: white;\n    box-shadow: 0 2px 20px rgba(0,0,0,0.08);\n    position: sticky;\n    top: 0;\n    z-index: 1000;\n}\n\n.header-inner {\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    padding: 15px 0;\n}\n\n.logo img {\n    height: 60px;\n    transition: transform 0.3s ease;\n}\n.logo:hover img { transform: scale(1.05); }\n\n/* Меню */\n.main-navigation ul {\n    display: flex;\n    list-style: none;\n    gap: 5px;\n    margin: 0;\n    padding: 0;\n}\n\n.main-navigation ul li { position: relative; }\n\n.main-navigation ul li a {\n    padding: 12px 18px;\n    font-weight: 500;\n    color: var(--color-primary);\n    border-radius: 6px;\n    transition: var(--transition);\n}\n\n.main-navigation ul li a:hover,\n.main-navigation ul li.current-menu-item > a {\n    color: var(--color-accent);\n    background: rgba(201, 169, 97, 0.1);\n}\n\n/* Выпадающее меню */\n.main-navigation ul ul {\n    position: absolute;\n    top: 100%;\n    left: 0;\n    background: white;\n    min-width: 240px;\n    border-radius: 8px;\n    box-shadow: 0 10px 40px rgba(0,0,0,0.15);\n    border-top: 3px solid var(--color-accent);\n    opacity: 0;\n    visibility: hidden;\n    transform: translateY(10px);\n    transition: var(--transition);\n    flex-direction: column;\n    padding: 8px 0;\n}\n\n.main-navigation ul li:hover > ul {\n    opacity: 1;\n    visibility: visible;\n    transform: translateY(0);\n}\n\n.main-navigation ul ul a {\n    padding: 10px 20px;\n    font-size: 14px;\n    border-left: 3px solid transparent;\n}\n\n.main-navigation ul ul a:hover {\n    background: var(--color-bg);\n    color: var(--color-accent);\n    border-left-color: var(--color-accent);\n    padding-left: 25px;\n}\n\n/* Стрелочка для подменю */\n.menu-item-has-children > a::after {\n    content: \'▼\';\n    font-size: 8px;\n    margin-left: 6px;\n    transition: transform 0.3s ease;\n}\n.menu-item-has-children:hover > a::after { transform: rotate(180deg); }\n\n/* Кнопка пожертвования в меню */\n.donate-menu-item a {\n    background: linear-gradient(135deg, var(--color-secondary), #a63042);\n    color: white !important;\n    padding: 10px 25px !important;\n    border-radius: 50px;\n    font-weight: 600;\n}\n.donate-menu-item a:hover {\n    transform: translateY(-2px);\n    box-shadow: 0 10px 30px rgba(139, 38, 53, 0.3);\n}\n\n/* ===== HERO СЕКЦИЯ ===== */\n.hero {\n    position: relative;\n    min-height: 550px;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    background: linear-gradient(135deg, var(--color-primary) 0%, #2d2d44 100%);\n    text-align: center;\n    color: white;\n    padding: 60px 20px;\n    overflow: hidden;\n}\n\n.hero::before {\n    content: \'\';\n    position: absolute;\n    inset: 0;\n    background: url(\'../images/hero-bg.jpg\') center/cover;\n    opacity: 0.15;\n}\n\n.hero-content {\n    position: relative;\n    z-index: 2;\n    max-width: 800px;\n}\n\n.hero-title {\n    font-size: 42px;\n    margin-bottom: 20px;\n    color: white;\n}\n\n.hero-subtitle {\n    font-size: 20px;\n    opacity: 0.95;\n    margin-bottom: 35px;\n}\n\n.hero-button {\n    display: inline-block;\n    padding: 16px 45px;\n    background: linear-gradient(135deg, var(--color-accent), var(--color-accent-hover));\n    color: var(--color-primary) !important;\n    border-radius: 50px;\n    font-weight: 600;\n    font-size: 16px;\n    box-shadow: 0 10px 30px rgba(201, 169, 97, 0.3);\n}\n.hero-button:hover {\n    transform: translateY(-3px);\n    box-shadow: 0 15px 40px rgba(201, 169, 97, 0.4);\n}\n\n/* ===== КАРТОЧКИ УСЛУГ ===== */\n.services-section {\n    padding: 80px 0;\n    background: white;\n}\n\n.section-title {\n    text-align: center;\n    margin-bottom: 50px;\n}\n.section-title h2 {\n    font-size: 32px;\n    margin-bottom: 15px;\n}\n.section-title p {\n    color: var(--color-text-light);\n    max-width: 600px;\n    margin: 0 auto;\n}\n\n.services-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));\n    gap: 30px;\n}\n\n.service-card {\n    background: var(--color-bg);\n    border-radius: var(--radius);\n    padding: 35px 30px;\n    text-align: center;\n    box-shadow: var(--shadow-card);\n    transition: var(--transition);\n    border-bottom: 3px solid transparent;\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n}\n\n.service-card:hover {\n    transform: translateY(-8px);\n    box-shadow: var(--shadow-hover);\n    border-bottom-color: var(--color-accent);\n}\n\n.service-icon {\n    width: 70px;\n    height: 70px;\n    background: linear-gradient(135deg, var(--color-accent), var(--color-accent-hover));\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    margin-bottom: 20px;\n    font-size: 28px;\n    color: var(--color-primary);\n}\n\n.service-card h3 {\n    font-size: 20px;\n    margin-bottom: 12px;\n}\n\n.service-card p {\n    color: var(--color-text-light);\n    margin-bottom: 20px;\n    flex-grow: 1;\n}\n\n.service-link {\n    color: var(--color-secondary);\n    font-weight: 500;\n    display: inline-flex;\n    align-items: center;\n    gap: 5px;\n}\n.service-link:hover { gap: 10px; }\n\n/* ===== БЛОК НОВОСТЕЙ ===== */\n.news-section {\n    padding: 80px 0;\n    background: var(--color-bg);\n}\n\n.news-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));\n    gap: 30px;\n}\n\n.news-card {\n    background: white;\n    border-radius: var(--radius);\n    overflow: hidden;\n    box-shadow: var(--shadow-card);\n    transition: var(--transition);\n}\n.news-card:hover {\n    transform: translateY(-5px);\n    box-shadow: var(--shadow-hover);\n}\n\n.news-image {\n    height: 200px;\n    background: #ddd;\n    background-size: cover;\n    background-position: center;\n}\n\n.news-content {\n    padding: 25px;\n}\n\n.news-date {\n    display: inline-block;\n    padding: 5px 15px;\n    background: var(--color-accent);\n    color: var(--color-primary);\n    border-radius: 20px;\n    font-size: 13px;\n    font-weight: 600;\n    margin-bottom: 12px;\n}\n\n.news-card h3 {\n    font-size: 18px;\n    margin-bottom: 10px;\n}\n\n.news-excerpt {\n    color: var(--color-text-light);\n    font-size: 14px;\n    margin-bottom: 15px;\n}\n\n.news-read-more {\n    color: var(--color-secondary);\n    font-weight: 500;\n    font-size: 14px;\n}\n\n/* ===== РАСПИСАНИЕ ===== */\n.schedule-section {\n    padding: 60px 0;\n}\n\n.schedule-table {\n    background: white;\n    border-radius: var(--radius);\n    box-shadow: var(--shadow-card);\n    overflow: hidden;\n}\n\n.schedule-row {\n    display: grid;\n    grid-template-columns: 1fr 2fr 1fr;\n    padding: 20px 25px;\n    border-bottom: 1px solid #eee;\n    align-items: center;\n    transition: var(--transition);\n}\n.schedule-row:last-child { border-bottom: none; }\n.schedule-row:hover { background: var(--color-bg); }\n\n.schedule-day { font-weight: 600; color: var(--color-primary); }\n.schedule-service { color: var(--color-text); }\n.schedule-time {\n    background: var(--color-accent);\n    color: var(--color-primary);\n    padding: 5px 15px;\n    border-radius: 20px;\n    font-weight: 600;\n    font-size: 14px;\n    text-align: center;\n}\n\n/* ===== ПОДВАЛ ===== */\n.site-footer {\n    background: var(--color-primary);\n    color: white;\n    padding: 60px 0 30px;\n}\n\n.footer-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));\n    gap: 40px;\n    margin-bottom: 40px;\n}\n\n.footer-widget h4 {\n    color: var(--color-accent);\n    margin-bottom: 20px;\n    font-size: 18px;\n}\n\n.footer-widget ul { list-style: none; }\n.footer-widget ul li { margin-bottom: 10px; }\n.footer-widget ul li a {\n    color: rgba(255,255,255,0.8);\n    transition: var(--transition);\n}\n.footer-widget ul li a:hover {\n    color: var(--color-accent);\n    padding-left: 5px;\n}\n\n.footer-bottom {\n    text-align: center;\n    padding-top: 25px;\n    border-top: 1px solid rgba(201, 169, 97, 0.3);\n    color: rgba(255,255,255,0.6);\n    font-size: 14px;\n}\n\n/* ===== АДАПТИВНОСТЬ ===== */\n@media (max-width: 992px) {\n    .main-navigation ul {\n        flex-wrap: wrap;\n        justify-content: center;\n    }\n    .hero-title { font-size: 36px; }\n}\n\n@media (max-width: 768px) {\n    .header-inner { flex-wrap: wrap; }\n    \n    .main-navigation {\n        order: 3;\n        width: 100%;\n        margin-top: 15px;\n    }\n    \n    .main-navigation ul {\n        flex-direction: column;\n        align-items: center;\n    }\n    \n    .main-navigation ul ul {\n        position: static;\n        opacity: 1;\n        visibility: visible;\n        transform: none;\n        box-shadow: none;\n        border-top: none;\n        border-left: 3px solid var(--color-accent);\n        margin-left: 15px;\n        margin-top: 5px;\n        padding-left: 10px;\n    }\n    \n    .hero-title { font-size: 28px; }\n    .hero-subtitle { font-size: 18px; }\n    \n    .schedule-row {\n        grid-template-columns: 1fr;\n        gap: 10px;\n        text-align: center;\n    }\n}','church-kadence-child','','inherit','closed','closed','','26-revision-v1','','','2026-03-08 12:24:13','2026-03-08 09:24:13','',26,'http://danil.local/?p=27',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (29,1,'2026-03-08 12:24:50','2026-03-08 09:24:50','/*\nTheme Name: Church Kadence Child\nTheme URI: http://danil.local/\nDescription: Дочерняя тема для храма на базе Kadence\nAuthor: Ваше Имя\nTemplate: kadence\nVersion: 1.0.0\nText Domain: church-kadence-child\n*/\n\n/* ===== БАЗОВЫЕ НАСТРОЙКИ ===== */\n:root {\n    --color-primary: #1a1a2e;\n    --color-accent: #c9a961;\n    --color-accent-hover: #b8960c;\n    --color-secondary: #8b2635;\n    --color-bg: #faf8f5;\n    --color-text: #2d2d2d;\n    --color-text-light: #666;\n    --shadow-card: 0 5px 20px rgba(0,0,0,0.08);\n    --shadow-hover: 0 15px 40px rgba(0,0,0,0.12);\n    --radius: 12px;\n    --transition: all 0.3s ease;\n}\n\n* { box-sizing: border-box; margin: 0; padding: 0; }\n\nbody {\n    font-family: \'Inter\', sans-serif;\n    color: var(--color-text);\n    background: var(--color-bg);\n    line-height: 1.6;\n}\n\nh1, h2, h3, h4 {\n    font-family: \'Playfair Display\', serif;\n    color: var(--color-primary);\n    line-height: 1.3;\n}\n\na { text-decoration: none; color: inherit; transition: var(--transition); }\nimg { max-width: 100%; height: auto; display: block; }\n\n.container {\n    max-width: 1200px;\n    margin: 0 auto;\n    padding: 0 20px;\n}\n\n/* ===== АНИМАЦИИ ===== */\n@keyframes fadeInUp {\n    from { opacity: 0; transform: translateY(30px); }\n    to { opacity: 1; transform: translateY(0); }\n}\n\n@keyframes goldShine {\n    0% { background-position: -200% center; }\n    100% { background-position: 200% center; }\n}\n\n.animate-fade-in { animation: fadeInUp 0.8s ease-out forwards; }\n.animate-fade-in-delay { animation: fadeInUp 0.8s ease-out 0.2s backwards; }\n\n.gold-text {\n    background: linear-gradient(90deg, var(--color-accent), #f0e6c8, var(--color-accent));\n    background-size: 200% auto;\n    -webkit-background-clip: text;\n    -webkit-text-fill-color: transparent;\n    animation: goldShine 3s linear infinite;\n}\n\n/* Плавное появление при скролле */\n.scroll-reveal {\n    opacity: 0;\n    transform: translateY(30px);\n    transition: all 0.6s ease;\n}\n.scroll-reveal.active {\n    opacity: 1;\n    transform: translateY(0);\n}\n\n/* ===== ШАПКА ===== */\n.site-header {\n    background: white;\n    box-shadow: 0 2px 20px rgba(0,0,0,0.08);\n    position: sticky;\n    top: 0;\n    z-index: 1000;\n}\n\n.header-inner {\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    padding: 15px 0;\n}\n\n.logo img {\n    height: 60px;\n    transition: transform 0.3s ease;\n}\n.logo:hover img { transform: scale(1.05); }\n\n/* Меню */\n.main-navigation ul {\n    display: flex;\n    list-style: none;\n    gap: 5px;\n    margin: 0;\n    padding: 0;\n}\n\n.main-navigation ul li { position: relative; }\n\n.main-navigation ul li a {\n    padding: 12px 18px;\n    font-weight: 500;\n    color: var(--color-primary);\n    border-radius: 6px;\n    transition: var(--transition);\n}\n\n.main-navigation ul li a:hover,\n.main-navigation ul li.current-menu-item > a {\n    color: var(--color-accent);\n    background: rgba(201, 169, 97, 0.1);\n}\n\n/* Выпадающее меню */\n.main-navigation ul ul {\n    position: absolute;\n    top: 100%;\n    left: 0;\n    background: white;\n    min-width: 240px;\n    border-radius: 8px;\n    box-shadow: 0 10px 40px rgba(0,0,0,0.15);\n    border-top: 3px solid var(--color-accent);\n    opacity: 0;\n    visibility: hidden;\n    transform: translateY(10px);\n    transition: var(--transition);\n    flex-direction: column;\n    padding: 8px 0;\n}\n\n.main-navigation ul li:hover > ul {\n    opacity: 1;\n    visibility: visible;\n    transform: translateY(0);\n}\n\n.main-navigation ul ul a {\n    padding: 10px 20px;\n    font-size: 14px;\n    border-left: 3px solid transparent;\n}\n\n.main-navigation ul ul a:hover {\n    background: var(--color-bg);\n    color: var(--color-accent);\n    border-left-color: var(--color-accent);\n    padding-left: 25px;\n}\n\n/* Стрелочка для подменю */\n.menu-item-has-children > a::after {\n    content: \'▼\';\n    font-size: 8px;\n    margin-left: 6px;\n    transition: transform 0.3s ease;\n}\n.menu-item-has-children:hover > a::after { transform: rotate(180deg); }\n\n/* Кнопка пожертвования в меню */\n.donate-menu-item a {\n    background: linear-gradient(135deg, var(--color-secondary), #a63042);\n    color: white !important;\n    padding: 10px 25px !important;\n    border-radius: 50px;\n    font-weight: 600;\n}\n.donate-menu-item a:hover {\n    transform: translateY(-2px);\n    box-shadow: 0 10px 30px rgba(139, 38, 53, 0.3);\n}\n\n/* ===== HERO СЕКЦИЯ ===== */\n.hero {\n    position: relative;\n    min-height: 550px;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    background: linear-gradient(135deg, var(--color-primary) 0%, #2d2d44 100%);\n    text-align: center;\n    color: white;\n    padding: 60px 20px;\n    overflow: hidden;\n}\n\n.hero::before {\n    content: \'\';\n    position: absolute;\n    inset: 0;\n    background: url(\'../images/hero-bg.jpg\') center/cover;\n    opacity: 0.15;\n}\n\n.hero-content {\n    position: relative;\n    z-index: 2;\n    max-width: 800px;\n}\n\n.hero-title {\n    font-size: 42px;\n    margin-bottom: 20px;\n    color: white;\n}\n\n.hero-subtitle {\n    font-size: 20px;\n    opacity: 0.95;\n    margin-bottom: 35px;\n}\n\n.hero-button {\n    display: inline-block;\n    padding: 16px 45px;\n    background: linear-gradient(135deg, var(--color-accent), var(--color-accent-hover));\n    color: var(--color-primary) !important;\n    border-radius: 50px;\n    font-weight: 600;\n    font-size: 16px;\n    box-shadow: 0 10px 30px rgba(201, 169, 97, 0.3);\n}\n.hero-button:hover {\n    transform: translateY(-3px);\n    box-shadow: 0 15px 40px rgba(201, 169, 97, 0.4);\n}\n\n/* ===== КАРТОЧКИ УСЛУГ ===== */\n.services-section {\n    padding: 80px 0;\n    background: white;\n}\n\n.section-title {\n    text-align: center;\n    margin-bottom: 50px;\n}\n.section-title h2 {\n    font-size: 32px;\n    margin-bottom: 15px;\n}\n.section-title p {\n    color: var(--color-text-light);\n    max-width: 600px;\n    margin: 0 auto;\n}\n\n.services-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));\n    gap: 30px;\n}\n\n.service-card {\n    background: var(--color-bg);\n    border-radius: var(--radius);\n    padding: 35px 30px;\n    text-align: center;\n    box-shadow: var(--shadow-card);\n    transition: var(--transition);\n    border-bottom: 3px solid transparent;\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n}\n\n.service-card:hover {\n    transform: translateY(-8px);\n    box-shadow: var(--shadow-hover);\n    border-bottom-color: var(--color-accent);\n}\n\n.service-icon {\n    width: 70px;\n    height: 70px;\n    background: linear-gradient(135deg, var(--color-accent), var(--color-accent-hover));\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    margin-bottom: 20px;\n    font-size: 28px;\n    color: var(--color-primary);\n}\n\n.service-card h3 {\n    font-size: 20px;\n    margin-bottom: 12px;\n}\n\n.service-card p {\n    color: var(--color-text-light);\n    margin-bottom: 20px;\n    flex-grow: 1;\n}\n\n.service-link {\n    color: var(--color-secondary);\n    font-weight: 500;\n    display: inline-flex;\n    align-items: center;\n    gap: 5px;\n}\n.service-link:hover { gap: 10px; }\n\n/* ===== БЛОК НОВОСТЕЙ ===== */\n.news-section {\n    padding: 80px 0;\n    background: var(--color-bg);\n}\n\n.news-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));\n    gap: 30px;\n}\n\n.news-card {\n    background: white;\n    border-radius: var(--radius);\n    overflow: hidden;\n    box-shadow: var(--shadow-card);\n    transition: var(--transition);\n}\n.news-card:hover {\n    transform: translateY(-5px);\n    box-shadow: var(--shadow-hover);\n}\n\n.news-image {\n    height: 200px;\n    background: #ddd;\n    background-size: cover;\n    background-position: center;\n}\n\n.news-content {\n    padding: 25px;\n}\n\n.news-date {\n    display: inline-block;\n    padding: 5px 15px;\n    background: var(--color-accent);\n    color: var(--color-primary);\n    border-radius: 20px;\n    font-size: 13px;\n    font-weight: 600;\n    margin-bottom: 12px;\n}\n\n.news-card h3 {\n    font-size: 18px;\n    margin-bottom: 10px;\n}\n\n.news-excerpt {\n    color: var(--color-text-light);\n    font-size: 14px;\n    margin-bottom: 15px;\n}\n\n.news-read-more {\n    color: var(--color-secondary);\n    font-weight: 500;\n    font-size: 14px;\n}\n\n/* ===== РАСПИСАНИЕ ===== */\n.schedule-section {\n    padding: 60px 0;\n}\n\n.schedule-table {\n    background: white;\n    border-radius: var(--radius);\n    box-shadow: var(--shadow-card);\n    overflow: hidden;\n}\n\n.schedule-row {\n    display: grid;\n    grid-template-columns: 1fr 2fr 1fr;\n    padding: 20px 25px;\n    border-bottom: 1px solid #eee;\n    align-items: center;\n    transition: var(--transition);\n}\n.schedule-row:last-child { border-bottom: none; }\n.schedule-row:hover { background: var(--color-bg); }\n\n.schedule-day { font-weight: 600; color: var(--color-primary); }\n.schedule-service { color: var(--color-text); }\n.schedule-time {\n    background: var(--color-accent);\n    color: var(--color-primary);\n    padding: 5px 15px;\n    border-radius: 20px;\n    font-weight: 600;\n    font-size: 14px;\n    text-align: center;\n}\n\n/* ===== ПОДВАЛ ===== */\n.site-footer {\n    background: var(--color-primary);\n    color: white;\n    padding: 60px 0 30px;\n}\n\n.footer-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));\n    gap: 40px;\n    margin-bottom: 40px;\n}\n\n.footer-widget h4 {\n    color: var(--color-accent);\n    margin-bottom: 20px;\n    font-size: 18px;\n}\n\n.footer-widget ul { list-style: none; }\n.footer-widget ul li { margin-bottom: 10px; }\n.footer-widget ul li a {\n    color: rgba(255,255,255,0.8);\n    transition: var(--transition);\n}\n.footer-widget ul li a:hover {\n    color: var(--color-accent);\n    padding-left: 5px;\n}\n\n.footer-bottom {\n    text-align: center;\n    padding-top: 25px;\n    border-top: 1px solid rgba(201, 169, 97, 0.3);\n    color: rgba(255,255,255,0.6);\n    font-size: 14px;\n}\n\n/* ===== АДАПТИВНОСТЬ ===== */\n@media (max-width: 992px) {\n    .main-navigation ul {\n        flex-wrap: wrap;\n        justify-content: center;\n    }\n    .hero-title { font-size: 36px; }\n}\n\n@media (max-width: 768px) {\n    .header-inner { flex-wrap: wrap; }\n    \n    .main-navigation {\n        order: 3;\n        width: 100%;\n        margin-top: 15px;\n    }\n    \n    .main-navigation ul {\n        flex-direction: column;\n        align-items: center;\n    }\n    \n    .main-navigation ul ul {\n        position: static;\n        opacity: 1;\n        visibility: visible;\n        transform: none;\n        box-shadow: none;\n        border-top: none;\n        border-left: 3px solid var(--color-accent);\n        margin-left: 15px;\n        margin-top: 5px;\n        padding-left: 10px;\n    }\n    \n    .hero-title { font-size: 28px; }\n    .hero-subtitle { font-size: 18px; }\n    \n    .schedule-row {\n        grid-template-columns: 1fr;\n        gap: 10px;\n        text-align: center;\n    }\n}','church-kadence-child','','inherit','closed','closed','','26-revision-v1','','','2026-03-08 12:24:50','2026-03-08 09:24:50','',26,'http://danil.local/?p=29',0,'revision','',0);
