INSERT INTO `wp_posts` VALUES (42,1,'2026-03-08 14:08:11','2026-03-08 11:08:11','<!-- wp:kadence/rowlayout {\"uniqueID\":\"40_9b421f-18\",\"columns\":1,\"customRowGutter\":[30,\"\",\"\"],\"columnGutter\":\"skinny\",\"tabletGutter\":\"default\",\"customGutter\":[16,32,\"\"],\"colLayout\":\"equal\",\"bgColor\":\"palette4\",\"align\":\"full\",\"inheritMaxWidth\":true,\"bgColorClass\":\"theme-palette4\",\"padding\":[\"xxl\",\"\",\"xxl\",\"\"],\"kbVersion\":2} -->\n<!-- wp:kadence/column {\"id\":2,\"borderWidth\":[\"\",\"\",\"\",\"\"],\"uniqueID\":\"40_1412e8-82\",\"textAlign\":[\"left\",\"\",\"\"],\"direction\":[\"vertical\",\"\",\"\"],\"gutter\":[0,\"\",\"\"],\"gutterVariable\":[\"custom\",\"\",\"\"],\"padding\":[\"0\",\"xl\",\"0\",\"\"],\"tabletPadding\":[\"0\",\"0\",\"0\",\"0\"],\"kbVersion\":2,\"className\":\"inner-column-2\"} -->\n<div class=\"wp-block-kadence-column kadence-column40_1412e8-82 kb-section-dir-vertical inner-column-2\"><div class=\"kt-inside-inner-col\"><!-- wp:kadence/advancedheading {\"uniqueID\":\"40_2aaa2c-e1\",\"align\":\"left\",\"color\":\"palette9\",\"fontWeight\":\"inherit\",\"margin\":[\"\",\"\",\"sm\",\"\"],\"marginType\":\"%\",\"mobileMargin\":[\"\",\"\",\"\",\"0\"],\"paddingType\":\"%\",\"padding\":[\"\",\"\",\"\",55],\"mobilePadding\":[\"\",\"\",\"\",\"0\"],\"markBorder\":\"\",\"markBorderStyles\":[{\"top\":[null,\"\",\"\"],\"right\":[null,\"\",\"\"],\"bottom\":[null,\"\",\"\"],\"left\":[null,\"\",\"\"],\"unit\":\"px\"}],\"colorClass\":\"theme-palette9\",\"fontSize\":[\"lg\",\"\",\"\"],\"fontHeight\":[1.2,\"\",\"\"],\"maxWidth\":[null,\"\",\"\"]} -->\n<h2 class=\"kt-adv-heading40_2aaa2c-e1 wp-block-kadence-advancedheading has-theme-palette-9-color has-text-color\" data-kb-block=\"kb-adv-heading40_2aaa2c-e1\">Specialized Church Choir Services Offered Online</h2>\n<!-- /wp:kadence/advancedheading -->\n\n<!-- wp:kadence/spacer {\"dividerWidth\":100,\"uniqueID\":\"40_a06bb7-0f\"} -->\n<div class=\"wp-block-kadence-spacer aligncenter kt-block