INSERT INTO `wp_posts` VALUES (79,1,'2026-03-08 14:37:10','2026-03-08 11:37:10','<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>2000г</strong>&nbsp;– Конкурс проектов на воссоздание собора. Победитель конкурса – архитектор В.Т. Головеров, ОАО «Краснодаргражданпроект»</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>17.12.2003г</strong>&nbsp; — Закладка Митрополитом Екатеринодарским и Кубанским Исидором воссоздаваемого собора .</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>15.06.2005г</strong>&nbsp;– Освящение крестов и колоколов нового собора Патриархом Московским и всея Руси Алексием II</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>28.05.2006г</strong>&nbsp;– Освящение воссозданного собора Митрополитом Смоленским&nbsp; и Калининградским Кириллом, избранным в 2009 г Патриархом Московским и всея Руси. Начало приходской деятельности.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"id\":80,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://danil.local/wp-content/uploads/2026/03/letopis.jpg\" alt=\"\" class=\"wp-image-80\"/></figure>\n<!-- /wp:image -->','История возрождения собора 2000 -2006г.г.','','publish','closed','closed','','%d0%b8%d1%81%d1%82%d0%be%d1%80%d0%b8%d1%8f-%d0%b2%d0%be%d0%b7%d1%80%d0%be%d0%b6%d0%b4%d0%b5%d0%bd%d0%b8%d1%8f-%d1%81%d0%be%d0%b1%d0%be%d1%80%d0%b0-2000-2006%d0%b3-%d0%b3','','','2026-03-08 15:20:59','2026-03-08 12:20:59','',0,'http://danil.local/?post_type=church_history&#038;p=79',0,'church_history','',0);
