INSERT INTO `wp_posts` VALUES (111,1,'2026-03-08 20:45:46','2026-03-08 17:45:46','<!-- wp:paragraph -->\n<p>Панихида — это православное заупокойное богослужение, на котором молятся об упокоении души умершего, прощении его грехов и даровании Царствия Небесного. Служба совершается священником в храме, на кладбище или дома, обычно в день смерти, на 3-й, 9-й, 40-й дни, годовщины, а также в родительские субботы. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Панихида','','publish','closed','closed','','%d0%bf%d0%b0%d0%bd%d0%b8%d1%85%d0%b8%d0%b4%d0%b0','','','2026-03-17 16:44:01','2026-03-17 13:44:01','',0,'http://danil.local/?post_type=church_service&#038;p=111',0,'church_service','',0);
